import{C as e,o as n,c as l,a5 as a,E as r}from"./chunks/framework.CW28V7p_.js";const k=JSON.parse('{"title":"4. Block production (produce vs skip)","description":"","frontmatter":{},"headers":[],"relativePath":"module-1/4-block-production.md","filePath":"module-1/4-block-production.md","lastUpdated":1780937944000}'),o={name:"module-1/4-block-production.md"},c=Object.assign(o,{setup(p){const i={id:"m1-4-block-production",title:"🧠 Mini-check: Block production",intro:"3 питання — що відбувається у leader slot.",questions:[{type:"order",q:"Постав у правильному порядку steps що leader робить у своєму 400ms slot:",items:["Broadcast shreds через turbine до інших validators","Open bank (start new in-progress block state)","Process transactions з TPU (включити у block)","Generate PoH ticks (continuous timestamping)","Vote за parent block (як validator)","Close bank (фіналізувати block state)"],correctOrder:[1,3,2,4,0,5],explanation:"Open bank → почати PoH (фіксує start time) → process TXs (заповнити block) → vote за previous (це теж TX) → broadcast shreds (паралельно з processing для latency) → close bank. PoH starts as soon as bank opens. Шреди можуть start broadcast як тільки перший shred ready (не чекати закриття)."},{type:"mcq",q:"Що з цього є валідними причинами skipped slot? (обери всі)",options:["Leader hardware замало fast — не встиг compile block за 400ms","Leader software крашнувся під час slot","Network лагав — leader не зміг достачити shreds до cluster","Інший validator забрав slot (race condition)"],correct:[0,1,2],explanation:'#1, #2, #3 — реальні причини skip. #4 НЕПРАВИЛЬНО: slot fixed для одного leader, ніхто не "забирає" race-style. Якщо leader fails — slot просто skipped.'},{type:"scenario",q:"Твій mainnet validator має skip rate 12% (підвищений). Що з цього варто investigate спочатку? Опиши 3-4 perspectivy.",ideal:`1. Hardware: CPU bottleneck. Run htop під час leader slot, дивись на high CPU/IOwait. Solution: upgrade CPU або move to faster server. Mainnet validator потребує AMD EPYC або Intel Xeon з high single-thread perf.

2. Network: high latency to peers. Run ping до major datacenter (e.g., Equinix). High RTT (>30ms до близьких peers) = шреди не доходять to cluster in time. Solution: change ISP/host, use peering.

3. Disk I/O: slow NVMe. Bank operations потребують fast write. Check iostat for high await. Solution: faster NVMe (Samsung 980 Pro або enterprise NVMe).

4. Software: новий agave version з regression. Check release notes if you upgraded recently. Solution: downgrade until issue fixed.

5. RAM: not enough RAM, OS swapping. Check free -h. Solution: 256GB+ для mainnet.

6. Логи: подивись solana logs для panic/error під час your leader slots specifically.`,explanation:"Ключове: думати multi-perspective (hardware/network/software). Якщо описала 3+ angles — повна відповідь. Bonus за specific debugging tools (htop, iostat, ping)."}]};return(h,s)=>{const t=e("Quiz");return n(),l("div",null,[s[0]||(s[0]=a("",60)),r(t,{data:i}),s[1]||(s[1]=a("",6))])}}});export{k as __pageData,c as default};
